def calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment):
    if principal <= 0 or annual_interest_rate < 0 or monthly_payment <= 0:
        raise ValueError("Invalid input values")

    monthly_interest_rate = annual_interest_rate / 12 / 100
    months = 0
    total_interest_paid = 0

    while principal > 0:
        interest_for_month = principal * monthly_interest_rate
        total_interest_paid += interest_for_month
        principal -= (monthly_payment - interest_for_month)
        months += 1

        if months > 1000:  # Prevent infinite loop for unrealistic scenarios
            raise ValueError("Loan cannot be paid back with the given monthly payment")

    return months, monthly_payment + (total_interest_paid / months)

def solve(principal, annual_interest_rate, monthly_payment):
    return calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment)
